import { debounce } from 'throttle-debounce';
import '../form-change-observer';

const manualModeToggle = document.querySelector('[data-manual-mode-input]');
const manualModeDisabled = document.querySelectorAll(
  '[data-manual-mode-disabled]'
);
const manualModeEnabled = document.querySelectorAll(
  '[data-manual-mode-enabled]'
);

function toggleManualMode(checkBox) {
  // In manual mode, only the model dropdown and count fields are visible
  manualModeEnabled.forEach((el) => {
    el.toggleAttribute('disabled', !checkBox.checked);
  });
  manualModeDisabled.forEach((el) => {
    el.toggleAttribute('disabled', checkBox.checked);
  });
}

toggleManualMode(manualModeToggle);
manualModeToggle.addEventListener('change', (e) => toggleManualMode(e.target));

const addBuildingButton = document.getElementById('add_building');
const removeBuildingButton = document.getElementById('remove_building');
const buildings = [...document.querySelectorAll('[data-building-formset]')];

function addBuilding(e) {
  e.stopPropagation();
  const nextId = buildings.findIndex((b) => b.classList.contains('_hidden'));
  if (nextId >= 0) {
    buildings[nextId].classList.remove('_hidden');
    buildings[nextId].querySelector('div[data-building-active] input').value =
      'True';
    updatePrices(e);
    if (nextId == buildings.length - 1) {
      addBuildingButton.toggleAttribute('disabled', true);
    }
    if (nextId > 0) {
      removeBuildingButton.toggleAttribute('disabled', false);
    }
  }
}

function removeBuilding(e) {
  e.stopPropagation();
  const nextReverseId = buildings
    .toReversed()
    .findIndex((b) => !b.classList.contains('_hidden'));

  if (nextReverseId >= 0) {
    const nextId = buildings.length - nextReverseId - 1;
    if (nextId > 0) {
      buildings[nextId].classList.add('_hidden');
      buildings[nextId].querySelector('div[data-building-active] input').value =
        '';
      updatePrices(e);
      if (nextId < buildings.length) {
        addBuildingButton.toggleAttribute('disabled', false);
      }
      if (nextId == 1) {
        removeBuildingButton.toggleAttribute('disabled', true);
      }
    }
  }
}

addBuildingButton.toggleAttribute(
  'disabled',
  buildings.findIndex((b) => b.classList.contains('_hidden')) === -1
);
removeBuildingButton.toggleAttribute(
  'disabled',
  buildings.filter((b) => !b.classList.contains('_hidden')).length === 1
);

addBuildingButton.addEventListener('click', addBuilding);
removeBuildingButton.addEventListener('click', removeBuilding);

const priceError = document.getElementById('spec-simulate-error');
const specSimulationCard = document.getElementById('spec-simulation-card');
const parentForm = document.getElementById('surface_form');

const debounceTimeout = 100;

function onSimulationLoad() {
  specSimulationCard
    .querySelectorAll('[data-summary-content]')
    .forEach((el) => {
      const originalHeight = el.offsetHeight;
      el.style.height = `${originalHeight}px`;
      el.classList.toggle('_skeleton-loading', true);
      el.innerHTML = '';
    });
  priceError.classList.add('_hidden');
}

function onSimulationError(error = '!') {
  specSimulationCard
    .querySelectorAll('[data-summary-content]')
    .forEach((el) => {
      el.classList.toggle('_skeleton-loading', false);
    });
  priceError.innerHTML = `<p class="_p-4 _text-white">${error}</p>`;
  priceError.classList.remove('_hidden');
}

function doSimulation() {
  const url = parentForm.getAttribute('data-preview-url');
  if (url === undefined) {
    return;
  }
  const data = new FormData(parentForm);
  window.cloud
    .postForm(url, {
      body: data,
    })
    .then((response) => response.json())
    .then((result) => {
      if (result.error) {
        return onSimulationError(result.error);
      }
      specSimulationCard.innerHTML = result.card;

      document.addEventListener('keypress', function (e) {
        if (e.which === 13) {
          e.preventDefault();
          e.stopPropagation();
        }
      });
    })
    .catch(onSimulationError);
}

const queueUpdate = debounce(debounceTimeout, doSimulation);

function updatePrices(e) {
  if (e) {
    const targetId = e && e.target && e.target.id;
    if (targetId === 'id_comment') {
      return;
    }
    const mapWrapperElem = document.querySelector('[data-tiling-map-wrapper]');
    if (mapWrapperElem && mapWrapperElem.contains(e.target)) {
      // Let Tetris propagate changes itself when it wants
      return;
    }

    const url = parentForm.getAttribute('data-preview-url');
    if (url === undefined) {
      return;
    }
    if (targetId && targetId.endsWith('-surface')) {
      return;
    }
  }
  onSimulationLoad();
  queueUpdate();
}

parentForm.addEventListener('change', updatePrices);
updatePrices();
